def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 5):
                    factor = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    priority += factor * np.sin(ratio * b / (a + 2)) * np.exp(-(a + b) / 10)
            priority += ((np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2) / (ratio + 1)
            for ex in range(1, 4):
                priority += np.power(np.log1p(ratio * ex), 1.7) * np.sin(ratio * ex * 2)
        elif 5 < ratio <= 8:
            for p1 in range(2, int(np.ceil(ratio)) + 5):
                for q1 in range(1, p1 + 3):
                    term = ((ratio - p1) ** 4) * np.cos(ratio * q1) / (q1 + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            for w in range(1, 6):
                priority -= np.sin(w * ratio) * (((ratio - 5) / w) ** 2)
        elif 3 <= ratio <= 5:
            s = 0
            factorial = 1
            for r1 in range(1, 15):
                factorial *= r1
                s += (((ratio - 3) ** r1) / (factorial * 2)) * np.cos(r1 * ratio * 1.2)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for t1 in range(1, 5):
                priority += np.cos(t1 * ratio * i) * ((ratio - 3) ** t1) / (t1 * 1.5)
        elif 1 <= ratio < 3:
            s = 0
            for n1 in range(1, 20):
                s += ((3 - ratio) ** n1) / (n1 ** 1.5 + 0.7)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m1 in range(1, 7):
                priority += np.sin(m1 * ratio * i * 0.9) * ((ratio - 1) ** m1) / (m1 ** 1.1)
            if i % 2 == 0:
                priority *= np.tanh(ratio)
            else:
                priority /= (np.cosh(ratio) + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for n2 in range(1, 12):
                s += ((1 - ratio) ** n2) / (n2 * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for j1 in range(1, 7):
                priority += ((1 - ratio) ** j1) * np.sin(j1 * item * 1.5) * 0.8
            priority += np.tanh(priority / (1 + ratio))
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k1 in range(1, 14):
                s += ((0.5 - ratio) ** k1) / (k1 * 2.8) * np.cos(k1 * ratio * 3)
            priority = s + 1 / (bin_cap + 2.5)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.1
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m2 in range(1, 9):
                priority += ((0.5 - ratio) ** m2) / (m2 * 8) * np.cos(item * m2 * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t2 in range(1, 15):
                s += ((0.2 - ratio) ** t2) / (t2 * 6) * np.sin(t2 * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u1 in range(1, 10):
                priority += ((0.2 - ratio) ** u1) / (u1 * 9) * np.cos(item * u1 * 0.9)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.05 - ratio) ** v) / (v * 8) * np.cos(v * item * 1.0)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.8) % 4 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 4) * 6
            for w1 in range(1, 11):
                priority += ((0.05 - ratio) ** w1) / (w1 * 10) * np.cos(item * w1 * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7 - np.cos(ratio * i * 0.9) * 0.3
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7 + np.sin(ratio * i * 0.9) * 0.3
        priorities[i] = priority
    return priorities
